// Placeholder: Format request for IRB API
// Ensure SOC2 compliance by using process.env or configured credentials

msg.url = "https://api.irbsearch.com/v1/search"; // PLACEHOLDER
msg.method = "POST";
msg.headers = {
    "Content-Type": "application/json",
    "Authorization": "Bearer " + (env.get("IRB_API_KEY") || "YOUR_API_KEY")
};

msg.payload = {
    firstName: msg.payload.firstName,
    lastName: msg.payload.lastName,
    address: msg.payload.address,
    includeRelatives: true
};

// FOR DEMO/BUILDING: Short-circuiting directly to parser since API isn't live yet
msg.demo_mode = true;

return msg;

let relatives = [];

if (msg.demo_mode) {
    // Sandbox output for UI testing
    relatives = [
        { name: "Jane Doe", phone: "+15551234567", relation: "Spouse" },
        { name: "John Doe Sr.", phone: "+15559876543", relation: "Father" }
    ];
} else {
    // Real parsing logic here
    // relatives = msg.payload.results.relatives.map(...)
}

msg.payload = {
    defendant: msg.payload.firstName + " " + msg.payload.lastName,
    relatives: relatives
};

// Save to global/flow context if needed for the button trigger
flow.set('last_irb_relatives', msg.payload);

return msg;

const data = flow.get('last_irb_relatives');
if (!data || !data.relatives || data.relatives.length === 0) {
    return null; // Nothing to do
}

return data.relatives.map(person => ({
    payload: {
        defendant: data.defendant,
        target_name: person.name,
        target_phone: person.phone,
        target_relation: person.relation
    }
}));

const def = msg.payload.defendant;
const name = msg.payload.target_name;

// The message template
const smsBody = `Hi ${name}, this is Shamrock Bail Bonds regarding ${def}. We are looking to see if you would like to assist with their bond and get them released. Please call or text us back immediately at 555-0199.`;

msg.url = `https://api.twilio.com/2010-04-01/Accounts/${env.get("TWILIO_ACCOUNT_SID")}/Messages.json`;
msg.method = "POST";

// Basic Auth for Twilio
const auth = Buffer.from(env.get("TWILIO_ACCOUNT_SID") + ':' + env.get("TWILIO_AUTH_TOKEN")).toString('base64');

msg.headers = {
    "Authorization": "Basic " + auth,
    "Content-Type": "application/x-www-form-urlencoded"
};

msg.payload = {
    "To": msg.payload.target_phone,
    "From": env.get("TWILIO_PHONE_NUMBER"),
    "Body": smsBody
};

return msg;

const def = msg.payload.defendant;
const name = msg.payload.target_name;

// The prompt script for Shannon
const prompt = `You are Shannon, an agent for Shamrock Bail Bonds. You are calling ${name} regarding ${def}. Politely ask if they are available to assist with ${def}'s bond and provide information.`;

msg.url = `https://api.elevenlabs.io/v1/convai/calls`;
msg.method = "POST";
msg.headers = {
    "xi-api-key": env.get("ELEVENLABS_API_KEY"),
    "Content-Type": "application/json"
};

// Note: This API format is an approximation. Actual ElevenLabs Outbound Dial API structure required here:
msg.payload = {
    phone_number: msg.payload.target_phone,
    agent_id: env.get("ELEVENLABS_SHANNON_AGENT_ID") || "YOUR_AGENT_ID",
    prompt_override: prompt
};

return msg;
